import os
from PIL import Image
from io import BytesIO
from boto3.session import Session
from selenium import webdriver
from selenium.webdriver.chrome.options import Options as ChromeOptions
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from flask_wtf.csrf import CSRFProtect

app = Flask(__name__)
csrf = CSRFProtect(app)

# AWS S3 configuration
AWS_ACCESS_KEY_ID = os.environ['AWS_ACCESS_KEY_ID']
AWS_SECRET_ACCESS_KEY = os.environ['AWS_SECRET_ACCESS_KEY']
AWS_BUCKET_NAME = 'your-bucket-name'

# Set up headless Chrome browser
chrome_options = ChromeOptions()
chrome_options.add_argument('--headless')
chrome_options.add_argument('--disable-gpu')

def take_screenshot(url):
    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()

    # Resize the image to 300x200
    img = Image.open(BytesIO(screenshot))
    img.thumbnail((300, 200))

    return img

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json['url']
    if not url.startswith('http'):
        return jsonify({'error': 'Invalid URL'}), 400

    # Validate the URL to prevent SSRF
    allowed_hosts = ['your-allowed-host.com', 'www.your-allowed-host.com']
    if any(url.endswith(host) for host in allowed_hosts):
        screenshot_img = take_screenshot(url)
        s3 = Session(aws_access_key_id=AWS_ACCESS_KEY_ID,
                     aws_secret_access_key=AWS_SECRET_ACCESS_KEY).resource('s3')
        s3.meta.client.upload_fileobj(BytesIO(screenshot_img.tobytes()), AWS_BUCKET_NAME, f'screenshots/{url}.png')
        return jsonify({'success': True}), 200
    else:
        return jsonify({'error': 'Invalid URL'}), 400

if __name__ == '__main__':
    app.run(debug=True)